{"version":3,"sources":["templates/taxi-selection.scss","templates/taxi-selection.css"],"names":[],"mappings":"AAAG;EACI,6BAAA;EACA,yBAAA;EACA,eAAA;ACCP;;ADEG;EACI,yBAAA;EACA,4CAAA;ACCP;;ADEG;EACI,YAAA;EACA,oBAAA;ACCP;;ADEG;EACI,uBAAA;EACA,gBAAA;EACA,kBAAA;EACA,WAAA;EACA,qBAAA;EACA,+BAAA;EACA,wBAAA;EACA,mCAAA;ACCP;;ADEG,gDAAA;AACA;EACI,aAAA;ACCP;;ADEG;EACI,kBAAA;EACA,QAAA;EACA,2BAAA;EACA,WAAA;EACA,YAAA;EACA,kBAAA;EACA,uBAAA;EACA,uCAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,eAAA;EACA,WAAA;ACCP;;ADEG;EACI,WAAA;ACCP;;ADEG;EACI,YAAA;ACCP;;ADEG;EACI,yBAAA;EACA,yBAAA;EACA,eAAA;EACA,WAAA;EACA,gBAAA;ACCP;;ADEG;EACI,yBAAA;EACA,4CAAA;ACCP;;ADEG;EACI,WAAA;EACA,WAAA;EACA,yBAAA;EACA,kBAAA;EACA,eAAA;ACCP;;ADEG;EACI,YAAA;EACA,yBAAA;EACA,kBAAA;EACA,UAAA;ACCP;;ADEG;EACI,cAAA;ACCP;;ADEG;EACI,yBAAA;EACA,cAAA;EACA,uBAAA;EACA,iBAAA;EACA,kBAAA;EACA,eAAA;EACA,yBAAA;ACCP;;ADEG;EACI,yBAAA;ACCP;;ADEG;EACI,yBAAA;EACA,YAAA;EACA,kBAAA;EACA,iBAAA;EACA,YAAA;EACA,eAAA;ACCP;;ADEG;EACI,WAAA;EACA,iBAAA;EACA,eAAA;EACA,eAAA;ACCP;;ADEG;EACI,WAAA;EACA,gCAAA;ACCP;;ADEG;EACI,aAAA;EACA,8BAAA;EACA,gCAAA;EACA,oBAAA;ACCP;;ADEG;EACI,kBAAA;EACA,SAAA;EACA,OAAA;EACA,QAAA;EACA,oCAAA;EACA,YAAA;EACA,aAAA;EACA,0BAAA;ACCP;;ADEG;EACI,yBAAA;EACA,YAAA;EACA,YAAA;EACA,kBAAA;EACA,kBAAA;EACA,eAAA;EACA,eAAA;ACCP;;ADEG;EACI,yBAAA;EACA,mBAAA;ACCP","file":"taxi-selection.css","sourcesContent":["   .vehicle-card {\n       border: 2px solid transparent;\n       transition: all 0.3s ease;\n       cursor: pointer;\n   }\n\n   .vehicle-card.selected {\n       border: 2px solid #6c63ff;\n       box-shadow: 0 0 15px rgba(108, 99, 255, 0.2);\n   }\n\n   .vehicle-card.disabled {\n       opacity: 0.5;\n       pointer-events: none;\n   }\n\n   .scroll-container {\n       scroll-behavior: smooth;\n       overflow-x: auto;\n       position: relative;\n       width: 100%;\n       scrollbar-width: none;\n       /* Hide scrollbar for Firefox */\n       -ms-overflow-style: none;\n       /* Hide scrollbar for IE and Edge */\n   }\n\n   /* Hide scrollbar for Chrome, Safari and Opera */\n   .scroll-container::-webkit-scrollbar {\n       display: none;\n   }\n\n   .scroll-btn {\n       position: absolute;\n       top: 50%;\n       transform: translateY(-50%);\n       width: 40px;\n       height: 40px;\n       border-radius: 50%;\n       background-color: white;\n       box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);\n       display: flex;\n       align-items: center;\n       justify-content: center;\n       cursor: pointer;\n       z-index: 10;\n   }\n\n   .scroll-btn.prev {\n       left: -15px;\n   }\n\n   .scroll-btn.next {\n       right: -15px;\n   }\n\n   .driver-card {\n       border: 1px solid #e0e0e0;\n       transition: all 0.3s ease;\n       cursor: pointer;\n       width: 100%;\n       max-width: 350px;\n   }\n\n   .driver-card.selected {\n       border: 2px solid #6c63ff;\n       box-shadow: 0 0 15px rgba(108, 99, 255, 0.2);\n   }\n\n   .progress-bar {\n       width: 100%;\n       height: 8px;\n       background-color: #e0e0e0;\n       border-radius: 4px;\n       margin-top: 8px;\n   }\n\n   .progress-fill {\n       height: 100%;\n       background-color: #34c759;\n       border-radius: 4px;\n       width: 20%;\n   }\n\n   .rating {\n       color: #34c759;\n   }\n\n   .claim-btn {\n       border: 1px solid #34c759;\n       color: #34c759;\n       background-color: white;\n       padding: 5px 15px;\n       border-radius: 4px;\n       font-size: 14px;\n       transition: all 0.3s ease;\n   }\n\n   .claim-btn:hover {\n       background-color: #f0fff0;\n   }\n\n   .get-started-btn {\n       background-color: #006633;\n       color: white;\n       border-radius: 4px;\n       padding: 8px 20px;\n       border: none;\n       font-size: 15px;\n   }\n\n   .tab-btn {\n       color: #666;\n       padding: 8px 15px;\n       font-size: 14px;\n       cursor: pointer;\n   }\n\n   .tab-btn.active {\n       color: #000;\n       border-bottom: 2px solid #34c759;\n   }\n\n   .stats-section {\n       display: flex;\n       justify-content: space-between;\n       border-bottom: 1px solid #e0e0e0;\n       padding-bottom: 10px;\n   }\n\n   .quick-look {\n       position: absolute;\n       bottom: 0;\n       left: 0;\n       right: 0;\n       background-color: rgba(0, 0, 0, 0.7);\n       color: white;\n       padding: 10px;\n       border-radius: 0 0 8px 8px;\n   }\n\n   .continue-btn {\n       background-color: #6c63ff;\n       color: white;\n       border: none;\n       padding: 10px 25px;\n       border-radius: 4px;\n       font-size: 16px;\n       cursor: pointer;\n   }\n\n   .continue-btn:disabled {\n       background-color: #b5b2ff;\n       cursor: not-allowed;\n   }",".vehicle-card {\n  border: 2px solid transparent;\n  transition: all 0.3s ease;\n  cursor: pointer;\n}\n\n.vehicle-card.selected {\n  border: 2px solid #6c63ff;\n  box-shadow: 0 0 15px rgba(108, 99, 255, 0.2);\n}\n\n.vehicle-card.disabled {\n  opacity: 0.5;\n  pointer-events: none;\n}\n\n.scroll-container {\n  scroll-behavior: smooth;\n  overflow-x: auto;\n  position: relative;\n  width: 100%;\n  scrollbar-width: none;\n  /* Hide scrollbar for Firefox */\n  -ms-overflow-style: none;\n  /* Hide scrollbar for IE and Edge */\n}\n\n/* Hide scrollbar for Chrome, Safari and Opera */\n.scroll-container::-webkit-scrollbar {\n  display: none;\n}\n\n.scroll-btn {\n  position: absolute;\n  top: 50%;\n  transform: translateY(-50%);\n  width: 40px;\n  height: 40px;\n  border-radius: 50%;\n  background-color: white;\n  box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  z-index: 10;\n}\n\n.scroll-btn.prev {\n  left: -15px;\n}\n\n.scroll-btn.next {\n  right: -15px;\n}\n\n.driver-card {\n  border: 1px solid #e0e0e0;\n  transition: all 0.3s ease;\n  cursor: pointer;\n  width: 100%;\n  max-width: 350px;\n}\n\n.driver-card.selected {\n  border: 2px solid #6c63ff;\n  box-shadow: 0 0 15px rgba(108, 99, 255, 0.2);\n}\n\n.progress-bar {\n  width: 100%;\n  height: 8px;\n  background-color: #e0e0e0;\n  border-radius: 4px;\n  margin-top: 8px;\n}\n\n.progress-fill {\n  height: 100%;\n  background-color: #34c759;\n  border-radius: 4px;\n  width: 20%;\n}\n\n.rating {\n  color: #34c759;\n}\n\n.claim-btn {\n  border: 1px solid #34c759;\n  color: #34c759;\n  background-color: white;\n  padding: 5px 15px;\n  border-radius: 4px;\n  font-size: 14px;\n  transition: all 0.3s ease;\n}\n\n.claim-btn:hover {\n  background-color: #f0fff0;\n}\n\n.get-started-btn {\n  background-color: #006633;\n  color: white;\n  border-radius: 4px;\n  padding: 8px 20px;\n  border: none;\n  font-size: 15px;\n}\n\n.tab-btn {\n  color: #666;\n  padding: 8px 15px;\n  font-size: 14px;\n  cursor: pointer;\n}\n\n.tab-btn.active {\n  color: #000;\n  border-bottom: 2px solid #34c759;\n}\n\n.stats-section {\n  display: flex;\n  justify-content: space-between;\n  border-bottom: 1px solid #e0e0e0;\n  padding-bottom: 10px;\n}\n\n.quick-look {\n  position: absolute;\n  bottom: 0;\n  left: 0;\n  right: 0;\n  background-color: rgba(0, 0, 0, 0.7);\n  color: white;\n  padding: 10px;\n  border-radius: 0 0 8px 8px;\n}\n\n.continue-btn {\n  background-color: #6c63ff;\n  color: white;\n  border: none;\n  padding: 10px 25px;\n  border-radius: 4px;\n  font-size: 16px;\n  cursor: pointer;\n}\n\n.continue-btn:disabled {\n  background-color: #b5b2ff;\n  cursor: not-allowed;\n}"]}